local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LGamePostProcess : LxBaseMgr
local LGamePostProcess = LxClass("LGamePostProcess", LxBaseMgr)
------------------------------------------------------------------
local CS = CS
local UnityEngine = UnityEngine
local PostProcess = CS.PostProcess
local PostProcessValueGroup = CS.PostProcessValueGroup
local typePostProcess = typeof(PostProcess)
------------------------------------------------------------------
function LGamePostProcess:Initialize()
	LxBaseMgr.Initialize(self)
end

function LGamePostProcess:Dispose()
	LxBaseMgr.Dispose(self)
end

function LGamePostProcess:ResetResolution()
	local postWidth = 512
	local postScale = postWidth / 640
	local postHeight = math.ceil(postWidth * UnityEngine.Screen.height / UnityEngine.Screen.width) 
	if (postHeight % 2) ~= 0 then
		postHeight = postHeight - 1
	end
	PostProcess.PostScale = postScale
	PostProcess.PostWidth = postWidth
	PostProcess.PostHeight = postHeight
end

function LGamePostProcess:InitPostProcess()
	local sceneCamera = gLGameScene:GetCurrentSceneCamera()
	local uiCamera = gLGameUI.GetUICamera()
	if not sceneCamera or not uiCamera then
		return
	end
	
	PostProcess.SceneCamera = sceneCamera
	PostProcess.UICamera = uiCamera
	--PostProcess.UIScaler = gLGameUI.GetUICanvasScaler()
	-- 延迟0.2秒Post
	PostProcess.PostDelayTime = 0
	self:ResetResolution()
end

function LGamePostProcess:InitNotchAnchor(maxNotchAnchor, minNotchAnchor)
	--if tolua.getfield(typePostProcess, "NotchAnchor") then
	--	local notchAnchor = Vector2.New(maxNotchAnchor.x, maxNotchAnchor.y)
	--	notchAnchor.y = 1.0 / notchAnchor.y
	--	notchAnchor.x = 1.0
	--	PostProcess.NotchAnchor = notchAnchor
	--else
		local minNotchAnchorX,minNotchAnchorY = minNotchAnchor.x,minNotchAnchor.y
		local maxNotchAnchorX,maxNotchAnchorY = maxNotchAnchor.x,maxNotchAnchor.y
		local x = 1 / (maxNotchAnchorX - minNotchAnchorX)
		local y = 1 / (maxNotchAnchorY - minNotchAnchorY)
		local minAnchor = Vector2.New(minNotchAnchorX, minNotchAnchorY)

		local totalY =(- minNotchAnchorY + maxNotchAnchorY)
		minAnchor.y = - minNotchAnchorY / totalY
		minAnchor.x = (1 - x) * 0.5

		local maxAnchor = Vector2.New(maxNotchAnchorX, maxNotchAnchorY)
		maxAnchor.y = (1 - minNotchAnchorY) / totalY
		maxAnchor.x = 1 + (x - 1) * 0.5
		PostProcess.NotchAnchorMin = minAnchor
		PostProcess.NotchAnchorMax = maxAnchor
	--end

end
------------------------------------------------------------------
-- test change map effect
function LGamePostProcess:ChangeMapEffect(camera, callback)
	if not camera then return end
	local postProcess = PostProcess.Get(camera.gameObject)
	if not postProcess then return end

	local trunTime = 0.5
	local reverseTime = 0.5
	local randValue = math.random(5)
	if randValue > 5 then
		trunTime = 0.2
		reverseTime = 0.1
		postProcess:ShowTrunEffect(1, trunTime, reverseTime)
		--postProcess:ShowTrunEffect(45, trunTime, reverseTime)
		--postProcess:ShowMotionBlur(0.05, trunTime, reverseTime)
	else
		trunTime = 0.5
		reverseTime = 0.2
		postProcess:ShowMotionBlur(0.05, trunTime, reverseTime)
	end
	
	LxTimer.DelayTimeCall(function()
		if callback then
			callback()
		end
	end, trunTime)
end
