-- Save RT
function LGamePostProcess:SaveRenderTexture(iCamType, blurZoom, blurStrength)
	iCamType = iCamType or 1
	blurZoom = blurZoom or 4
	blurStrength = blurStrength or 0.6
	PostProcess.SaveRenderTexture(iCamType, blurZoom, blurStrength)
end
------------------------------------------------------------------
-- GrayUI
function LGamePostProcess:ShowUIGray(aniTime, reverseTime, callback)
	local camera = gLGameUI:GetCSUICamera()
	if not camera then return end

	local matValues = {
		["_Saturation"] = { valueType = 2, value = 1 }
	}
	self:ShowEffectSimple(camera, "GrayUI", matValues, aniTime, reverseTime, callback)
end

function LGamePostProcess:HideUIGray(aniTime)
	local camera = gLGameUI:GetCSUICamera()
	if not camera then return end

	aniTime = aniTime or -1
	if aniTime > 0 then
		local matValues = {
			["_Saturation"] = { valueType = 2, value = 1 }
		}
		self:ShowEffectSimple(camera, "Gray", matValues, 0, aniTime, function()
			self:HidePostEffect(camera, "Gray")
		end)
	else
		self:HidePostEffect(camera, "Gray")
	end
end


-- Gray
function LGamePostProcess:ShowSceneGray(aniTime, reverseTime, callback)
	local camera = gLGameScene:GetCurrentSceneCamera()
	if not camera then return end
	
	local matValues = {
		["_Saturation"] = { valueType = 2, value = 1 }
	}
	self:ShowEffectSimple(camera, "Gray", matValues, aniTime, reverseTime, callback)
end

function LGamePostProcess:HideSceneGray(aniTime)
	local camera = gLGameScene:GetCurrentSceneCamera()
	if not camera then return end
	aniTime = aniTime or -1
	if aniTime > 0 then
		local matValues = {
			["_Saturation"] = { valueType = 2, value = 1 }
		}
		self:ShowEffectSimple(camera, "Gray", matValues, 0, aniTime, function()
			self:HidePostEffect(camera, "Gray")
		end)
	else
		self:HidePostEffect(camera, "Gray")
	end
end

-- 幻影模糊
function LGamePostProcess:ShowSceneMotionBlur(blurRadius, blurStrength, aniTime, reverseTime, callback)
	local camera = gLGameScene:GetCurrentSceneCamera()
	if not camera then return end

	local matValues = {
		["_BlurRadius"] = { valueType = 1, value = blurRadius or 0 },
		["_BlurStrength"] = { valueType = 2, value = blurStrength or 0}
	}
	local function onMotionEnd()
		self:HidePostEffect(camera, "MotionBlur")
		if callback then
			callback()
		end
	end
	self:ShowEffectSimple(camera, "MotionBlur", matValues, aniTime, reverseTime, onMotionEnd)
end
-- 均值模糊
function LGamePostProcess:ShowSceneAverageBlur(bBlur, postTime, reverseTime, callback)
	local camera = gLGameScene:GetCurrentSceneCamera()
	if not camera then return end

	if bBlur then
		self:ShowEffectBlur(camera, 4, 0.6, postTime, reverseTime, callback)
	else
		self:HidePostEffect(camera, "AverageBlur")
	end
	
end
------------------------------------------------------------------
-- C# Simple
function LGamePostProcess:ShowEffectSimple(camera, matKey, matValues, postTime, reverseTime, callback)
	if not camera then return end

	local postProcess = PostProcess.Get(camera.gameObject, true)
	if not postProcess then return end
	
	matValues = matValues or {}
	postTime = postTime or -1
	reverseTime = reverseTime or -1
	
	local valueGroup = PostProcessValueGroup.New()
	for key,item in pairs(matValues) do
		valueGroup:AddValue(key, item.valueType, item.value)
	end
	postProcess:ShowEffectSimple(matKey, valueGroup, postTime, reverseTime, callback)
end
------------------------------------------------------------------
-- C# Blur 
function LGamePostProcess:ShowEffectBlur(camera, blurZoom, blurStrength, postTime, reverseTime, callback)
	if not camera then return end

	local postProcess = PostProcess.Get(camera.gameObject)
	if not postProcess then return end
	
	local matValues = {
		["blurZoom"] = { valueType = 0, value = blurZoom or 4 },
		["blurStrength"] = { valueType = 0, value = blurStrength or 0.5 }
	}
	postTime = postTime or 0
	reverseTime = reverseTime or 0
	
	local valueGroup = PostProcessValueGroup.New()
	for key,item in pairs(matValues) do
		valueGroup:AddValue(key, item.valueType, item.value)
	end
	postProcess:ShowEffectBlur("AverageBlur", valueGroup, postTime, reverseTime, callback)
end
------------------------------------------------------------------
-- 删除指定屏幕特效
function LGamePostProcess:HidePostEffect(camera, matKey)
	if not camera then return end

	local postProcess = PostProcess.Get(camera.gameObject, false)
	if not postProcess then return end
	
	postProcess:HidePostEffect(matKey, true)
end

------------------------------------------------------------------
return LGamePostProcess

